import{_ as e,o,c as s,a2 as a}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"Claude Code — Tool System","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/claude-code/tool-system.md","filePath":"research/agents/claude-code/tool-system.md"}'),n={name:"research/agents/claude-code/tool-system.md"};function d(r,t,i,l,c,p){return o(),s("div",null,[...t[0]||(t[0]=[a(`<h1 id="claude-code-—-tool-system" tabindex="-1">Claude Code — Tool System <a class="header-anchor" href="#claude-code-—-tool-system" aria-label="Permalink to &quot;Claude Code — Tool System&quot;">​</a></h1><blockquote><p>Complete catalog of known tools, their permission requirements, and the MCP integration layer.</p></blockquote><h2 id="tool-catalog" tabindex="-1">Tool Catalog <a class="header-anchor" href="#tool-catalog" aria-label="Permalink to &quot;Tool Catalog&quot;">​</a></h2><p>Claude Code&#39;s tools are the mechanism that make it agentic. Without tools, Claude can only respond with text. With tools, it can act: read code, edit files, run commands, search the web, and interact with external services.</p><h3 id="core-tools-reference" tabindex="-1">Core Tools Reference <a class="header-anchor" href="#core-tools-reference" aria-label="Permalink to &quot;Core Tools Reference&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tool</th><th>Description</th><th>Permission Required</th><th>Category</th></tr></thead><tbody><tr><td><code>Read</code></td><td>Reads file contents</td><td>No</td><td>File Operations</td></tr><tr><td><code>Edit</code></td><td>Makes targeted edits to specific files</td><td>Yes</td><td>File Operations</td></tr><tr><td><code>Write</code></td><td>Creates or overwrites files</td><td>Yes</td><td>File Operations</td></tr><tr><td><code>NotebookEdit</code></td><td>Modifies Jupyter notebook cells</td><td>Yes</td><td>File Operations</td></tr><tr><td><code>Bash</code></td><td>Executes shell commands</td><td>Yes</td><td>Execution</td></tr><tr><td><code>Grep</code></td><td>Searches for patterns in file contents (regex)</td><td>No</td><td>Search</td></tr><tr><td><code>Glob</code></td><td>Finds files based on pattern matching</td><td>No</td><td>Search</td></tr><tr><td><code>WebFetch</code></td><td>Fetches content from a URL</td><td>Yes</td><td>Web</td></tr><tr><td><code>WebSearch</code></td><td>Performs web searches</td><td>Yes</td><td>Web</td></tr><tr><td><code>Agent</code></td><td>Spawns a sub-agent with its own context window</td><td>No</td><td>Orchestration</td></tr><tr><td><code>AskUserQuestion</code></td><td>Asks multiple-choice questions to gather requirements</td><td>No</td><td>Orchestration</td></tr><tr><td><code>EnterPlanMode</code></td><td>Switches to plan mode for analysis before coding</td><td>No</td><td>Orchestration</td></tr><tr><td><code>ExitPlanMode</code></td><td>Presents a plan for approval and exits plan mode</td><td>Yes</td><td>Orchestration</td></tr><tr><td><code>EnterWorktree</code></td><td>Creates an isolated git worktree and switches into it</td><td>No</td><td>Orchestration</td></tr><tr><td><code>ExitWorktree</code></td><td>Exits a worktree session</td><td>No</td><td>Orchestration</td></tr><tr><td><code>Skill</code></td><td>Executes a skill within the main conversation</td><td>Yes</td><td>Orchestration</td></tr><tr><td><code>LSP</code></td><td>Code intelligence via language servers (type errors, go-to-definition, find references)</td><td>No</td><td>Code Intelligence</td></tr><tr><td><code>ToolSearch</code></td><td>Searches for deferred MCP tools on demand</td><td>No</td><td>MCP</td></tr><tr><td><code>ListMcpResourcesTool</code></td><td>Lists resources exposed by MCP servers</td><td>No</td><td>MCP</td></tr><tr><td><code>ReadMcpResourceTool</code></td><td>Reads a specific MCP resource by URI</td><td>No</td><td>MCP</td></tr><tr><td><code>CronCreate</code></td><td>Schedules a recurring/one-shot prompt within the session</td><td>No</td><td>Scheduling</td></tr><tr><td><code>CronDelete</code></td><td>Cancels a scheduled task by ID</td><td>No</td><td>Scheduling</td></tr><tr><td><code>CronList</code></td><td>Lists all scheduled tasks</td><td>No</td><td>Scheduling</td></tr><tr><td><code>TaskCreate</code></td><td>Creates a new task in the task list</td><td>No</td><td>Task Management</td></tr><tr><td><code>TaskGet</code></td><td>Retrieves task details</td><td>No</td><td>Task Management</td></tr><tr><td><code>TaskList</code></td><td>Lists tasks with status</td><td>No</td><td>Task Management</td></tr><tr><td><code>TaskUpdate</code></td><td>Updates task status/dependencies</td><td>No</td><td>Task Management</td></tr><tr><td><code>TaskOutput</code></td><td>Retrieves output from a background task</td><td>No</td><td>Task Management</td></tr><tr><td><code>TaskStop</code></td><td>Kills a running background task</td><td>No</td><td>Task Management</td></tr><tr><td><code>TodoWrite</code></td><td>Manages session task checklist (non-interactive/SDK mode)</td><td>No</td><td>Task Management</td></tr></tbody></table><h3 id="tool-categories" tabindex="-1">Tool Categories <a class="header-anchor" href="#tool-categories" aria-label="Permalink to &quot;Tool Categories&quot;">​</a></h3><p><strong>File Operations</strong> — Read, search, and modify files:</p><ul><li><code>Read</code> is permission-free; <code>Edit</code> requires session-level approval; <code>Write</code> requires per-use approval</li><li><code>Edit</code> applies to all built-in tools that edit files</li><li><code>Read</code> rules also apply (best-effort) to Grep and Glob</li></ul><p><strong>Execution</strong> — Run shell commands:</p><ul><li><code>Bash</code> runs each command in a separate process</li><li>Working directory persists across commands; environment variables do not</li><li>Compound commands (<code>&amp;&amp;</code>) save separate permission rules per subcommand</li><li>Virtualenv/conda must be activated before launching Claude Code</li></ul><p><strong>Search</strong> — Find files and content:</p><ul><li><code>Grep</code> for content search (regex), <code>Glob</code> for file name patterns</li><li>Both are read-only and permission-free</li></ul><p><strong>Web</strong> — External information:</p><ul><li><code>WebFetch</code> for specific URLs, <code>WebSearch</code> for queries</li><li>Both require permission; <code>WebFetch</code> supports domain-based rules</li></ul><p><strong>Code Intelligence</strong> — Via language servers:</p><ul><li><code>LSP</code> reports type errors automatically after file edits</li><li>Supports: go-to-definition, find references, type info, symbols, implementations, call hierarchies</li><li>Requires a code intelligence plugin with the relevant language server binary</li></ul><p><strong>Orchestration</strong> — Agent coordination:</p><ul><li><code>Agent</code> spawns sub-agents in separate context windows</li><li><code>AskUserQuestion</code> for structured requirement gathering</li><li>Plan mode tools for analysis-before-action workflow</li><li>Worktree tools for parallel isolated sessions</li></ul><h2 id="permission-system" tabindex="-1">Permission System <a class="header-anchor" href="#permission-system" aria-label="Permalink to &quot;Permission System&quot;">​</a></h2><h3 id="permission-tiers" tabindex="-1">Permission Tiers <a class="header-anchor" href="#permission-tiers" aria-label="Permalink to &quot;Permission Tiers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tool Type</th><th>Examples</th><th>Approval Required</th><th>&quot;Don&#39;t ask again&quot; Behavior</th></tr></thead><tbody><tr><td>Read-only</td><td>File reads, Grep, Glob</td><td>No</td><td>N/A</td></tr><tr><td>Bash commands</td><td>Shell execution</td><td>Yes</td><td>Permanently per project + command</td></tr><tr><td>File modification</td><td>Edit, Write</td><td>Yes</td><td>Until session end</td></tr></tbody></table><h3 id="permission-modes" tabindex="-1">Permission Modes <a class="header-anchor" href="#permission-modes" aria-label="Permalink to &quot;Permission Modes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Mode</th><th>Description</th><th>How to Activate</th></tr></thead><tbody><tr><td><code>default</code></td><td>Prompts for permission on first use of each tool</td><td>Default behavior</td></tr><tr><td><code>acceptEdits</code></td><td>Auto-accepts file edits; still asks for Bash</td><td><code>Shift+Tab</code> once</td></tr><tr><td><code>plan</code></td><td>Read-only — Claude can analyze but not modify</td><td><code>Shift+Tab</code> twice</td></tr><tr><td><code>dontAsk</code></td><td>Auto-denies unless pre-approved via allow rules</td><td>Settings</td></tr><tr><td><code>bypassPermissions</code></td><td>Skips all prompts except protected directories</td><td><code>--dangerously-skip-permissions</code></td></tr></tbody></table><h3 id="permission-rule-syntax" tabindex="-1">Permission Rule Syntax <a class="header-anchor" href="#permission-rule-syntax" aria-label="Permalink to &quot;Permission Rule Syntax&quot;">​</a></h3><p>Rules follow the format <code>Tool</code> or <code>Tool(specifier)</code>:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span># Match all uses of a tool</span></span>
<span class="line"><span>Bash          # All bash commands</span></span>
<span class="line"><span>WebFetch      # All web fetches</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Exact match with specifier</span></span>
<span class="line"><span>Bash(npm run build)      # Only this specific command</span></span>
<span class="line"><span>Read(./.env)             # Only this file</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Wildcard patterns (glob-style)</span></span>
<span class="line"><span>Bash(npm run *)          # npm run anything</span></span>
<span class="line"><span>Bash(git commit *)       # git commit with any args</span></span>
<span class="line"><span>Bash(* --version)        # Any --version command</span></span>
<span class="line"><span>Read(src/**)             # All files under src/</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Domain-based web fetch</span></span>
<span class="line"><span>WebFetch(domain:example.com)</span></span>
<span class="line"><span></span></span>
<span class="line"><span># MCP tool permissions</span></span>
<span class="line"><span>mcp__puppeteer                      # All puppeteer tools</span></span>
<span class="line"><span>mcp__puppeteer__puppeteer_navigate  # Specific tool</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Sub-agent permissions</span></span>
<span class="line"><span>Agent(Explore)         # The Explore sub-agent</span></span>
<span class="line"><span>Agent(my-custom-agent) # A custom sub-agent</span></span></code></pre></div><h3 id="rule-evaluation-order" tabindex="-1">Rule Evaluation Order <a class="header-anchor" href="#rule-evaluation-order" aria-label="Permalink to &quot;Rule Evaluation Order&quot;">​</a></h3><p>Rules evaluate in strict order: <strong>deny → ask → allow</strong>. First match wins.</p><ul><li>A deny in managed settings <strong>cannot</strong> be overridden by any other level</li><li>A deny at project level overrides an allow at user level</li><li>Managed settings have highest precedence, then CLI args, local, project, user</li></ul><h3 id="permission-configuration-example" tabindex="-1">Permission Configuration Example <a class="header-anchor" href="#permission-configuration-example" aria-label="Permalink to &quot;Permission Configuration Example&quot;">​</a></h3><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">permissions</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">    &quot;</span><span style="color:#89B4FA;">allow</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span></span>
<span class="line"><span style="color:#A6E3A1;">      &quot;Bash(npm run lint)&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#A6E3A1;">      &quot;Bash(npm run test *)&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#A6E3A1;">      &quot;Read(~/.zshrc)&quot;</span></span>
<span class="line"><span style="color:#9399B2;">    ],</span></span>
<span class="line"><span style="color:#9399B2;">    &quot;</span><span style="color:#89B4FA;">deny</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span></span>
<span class="line"><span style="color:#A6E3A1;">      &quot;Bash(curl *)&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#A6E3A1;">      &quot;Read(./.env)&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#A6E3A1;">      &quot;Read(./.env.*)&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#A6E3A1;">      &quot;Read(./secrets/**)&quot;</span></span>
<span class="line"><span style="color:#9399B2;">    ],</span></span>
<span class="line"><span style="color:#9399B2;">    &quot;</span><span style="color:#89B4FA;">defaultMode</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;acceptEdits&quot;</span></span>
<span class="line"><span style="color:#9399B2;">  }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><h3 id="read-edit-path-patterns" tabindex="-1">Read/Edit Path Patterns <a class="header-anchor" href="#read-edit-path-patterns" aria-label="Permalink to &quot;Read/Edit Path Patterns&quot;">​</a></h3><p>Path rules follow gitignore specification with four pattern types:</p><table tabindex="0"><thead><tr><th>Pattern</th><th>Meaning</th><th>Example</th></tr></thead><tbody><tr><td><code>//path</code></td><td>Absolute from filesystem root</td><td><code>Read(//Users/alice/secrets/**)</code></td></tr><tr><td><code>~/path</code></td><td>From home directory</td><td><code>Read(~/Documents/*.pdf)</code></td></tr><tr><td><code>/path</code></td><td>Relative to project root</td><td><code>Edit(/src/**/*.ts)</code></td></tr><tr><td><code>path</code> or <code>./path</code></td><td>Relative to current directory</td><td><code>Read(*.env)</code></td></tr></tbody></table><h2 id="bash-tool-behavior" tabindex="-1">Bash Tool Behavior <a class="header-anchor" href="#bash-tool-behavior" aria-label="Permalink to &quot;Bash Tool Behavior&quot;">​</a></h2><p>Key details about the Bash tool:</p><ul><li><strong>Process isolation</strong>: Each command runs in a separate process</li><li><strong>Working directory persists</strong>: <code>cd</code> in one command affects the next</li><li><strong>Environment variables do NOT persist</strong>: <code>export</code> in one command is lost in the next</li><li><strong>Workaround for env vars</strong>: Set <code>CLAUDE_ENV_FILE</code> to a shell script, or use a SessionStart hook</li><li><strong>Reset to project dir</strong>: Set <code>CLAUDE_BASH_MAINTAIN_PROJECT_WORKING_DIR=1</code></li></ul><h2 id="mcp-integration" tabindex="-1">MCP Integration <a class="header-anchor" href="#mcp-integration" aria-label="Permalink to &quot;MCP Integration&quot;">​</a></h2><h3 id="what-mcp-provides" tabindex="-1">What MCP Provides <a class="header-anchor" href="#what-mcp-provides" aria-label="Permalink to &quot;What MCP Provides&quot;">​</a></h3><p>MCP (Model Context Protocol) is an open standard for AI-tool integrations. Claude Code connects to MCP servers to access external tools:</p><ul><li><strong>Issue trackers</strong>: Jira, Linear, GitHub Issues</li><li><strong>Databases</strong>: PostgreSQL, MySQL via dbhub</li><li><strong>Monitoring</strong>: Sentry, Datadog</li><li><strong>Design</strong>: Figma</li><li><strong>Communication</strong>: Slack, Gmail</li><li><strong>Browsers</strong>: Playwright, Puppeteer</li><li><strong>Code platforms</strong>: GitHub, GitLab</li></ul><h3 id="mcp-transports" tabindex="-1">MCP Transports <a class="header-anchor" href="#mcp-transports" aria-label="Permalink to &quot;MCP Transports&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Transport</th><th>Use Case</th></tr></thead><tbody><tr><td><code>http</code></td><td>Remote HTTP servers (recommended for cloud services)</td></tr><tr><td><code>sse</code></td><td>Server-Sent Events (older remote protocol)</td></tr><tr><td><code>stdio</code></td><td>Local process servers (direct system access)</td></tr><tr><td><code>ws</code></td><td>WebSocket connections</td></tr></tbody></table><h3 id="mcp-scopes" tabindex="-1">MCP Scopes <a class="header-anchor" href="#mcp-scopes" aria-label="Permalink to &quot;MCP Scopes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Scope</th><th>Location</th><th>Shared?</th></tr></thead><tbody><tr><td><strong>Local</strong></td><td><code>~/.claude.json</code> per project path</td><td>No</td></tr><tr><td><strong>Project</strong></td><td><code>.mcp.json</code> in project root (git-committed)</td><td>Yes</td></tr><tr><td><strong>User</strong></td><td><code>~/.claude.json</code> globally</td><td>No</td></tr></tbody></table><h3 id="mcp-tool-search" tabindex="-1">MCP Tool Search <a class="header-anchor" href="#mcp-tool-search" aria-label="Permalink to &quot;MCP Tool Search&quot;">​</a></h3><p>When many MCP servers are configured, tool definitions consume significant context. <strong>Tool Search</strong> solves this:</p><ul><li>Automatically enabled when MCP tools exceed 10% of context window</li><li>MCP tools are deferred rather than preloaded</li><li>Claude uses a search tool to discover relevant MCP tools on demand</li><li>Only tools actually needed are loaded into context</li><li>Configurable via <code>ENABLE_TOOL_SEARCH</code> environment variable</li></ul><h3 id="using-claude-code-as-an-mcp-server" tabindex="-1">Using Claude Code AS an MCP Server <a class="header-anchor" href="#using-claude-code-as-an-mcp-server" aria-label="Permalink to &quot;Using Claude Code AS an MCP Server&quot;">​</a></h3><p>Claude Code itself can serve as an MCP server for other applications:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;font-style:italic;">claude</span><span style="color:#A6E3A1;"> mcp</span><span style="color:#A6E3A1;"> serve</span><span style="color:#6C7086;font-style:italic;">   # Start Claude as a stdio MCP server</span></span></code></pre></div><p>This allows Claude Desktop or other MCP clients to use Claude Code as a tool provider.</p><h2 id="hooks-system" tabindex="-1">Hooks System <a class="header-anchor" href="#hooks-system" aria-label="Permalink to &quot;Hooks System&quot;">​</a></h2><p>Hooks are deterministic shell scripts that run at lifecycle points. Unlike CLAUDE.md (advisory), hooks are enforced:</p><h3 id="hook-events" tabindex="-1">Hook Events <a class="header-anchor" href="#hook-events" aria-label="Permalink to &quot;Hook Events&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Event</th><th>When It Fires</th></tr></thead><tbody><tr><td><code>PreToolUse</code></td><td>Before a tool call — can deny, force prompt, or allow</td></tr><tr><td><code>PostToolUse</code></td><td>After a tool call completes</td></tr><tr><td><code>SessionStart</code></td><td>When a session begins</td></tr><tr><td><code>Notification</code></td><td>When Claude needs attention (permission, idle, auth)</td></tr><tr><td><code>WorktreeCreate</code></td><td>When a worktree is created</td></tr><tr><td><code>WorktreeRemove</code></td><td>When a worktree is removed</td></tr><tr><td><code>Elicitation</code></td><td>When MCP server requests structured input</td></tr></tbody></table><h3 id="hook-precedence-with-permissions" tabindex="-1">Hook Precedence with Permissions <a class="header-anchor" href="#hook-precedence-with-permissions" aria-label="Permalink to &quot;Hook Precedence with Permissions&quot;">​</a></h3><p>PreToolUse hooks run before the permission prompt. A hook can:</p><ul><li><strong>Deny</strong> the tool call (exit code 2)</li><li><strong>Force a prompt</strong> — override auto-allow to ask</li><li><strong>Skip the prompt</strong> — but deny/ask rules still override</li></ul><p>This means hooks extend but cannot bypass the permission system.</p><h2 id="key-observations" tabindex="-1">Key Observations <a class="header-anchor" href="#key-observations" aria-label="Permalink to &quot;Key Observations&quot;">​</a></h2><ol><li><p><strong>Tool-use is native API</strong>: Claude Code uses Anthropic&#39;s built-in tool-use (function-calling) protocol, not prompt injection. Tools are defined in the API request, and the model returns structured <code>tool_use</code> blocks.</p></li><li><p><strong>Permission granularity is exceptional</strong>: The allow/ask/deny system with glob patterns, domain matching, path patterns, and MCP tool matching is the most granular permission system in any coding agent.</p></li><li><p><strong>Bash is the power tool and the risk</strong>: Most capability flows through Bash — builds, tests, git, package managers. The permission system and sandboxing are primarily designed to control Bash.</p></li><li><p><strong>LSP integration via plugins</strong>: Code intelligence (type checking, go-to-definition) requires separate plugin installation, not built into core. This is a modular design choice.</p></li><li><p><strong>MCP Tool Search is context-aware</strong>: Dynamically loading MCP tools only when needed is a sophisticated approach to the context budget problem. It&#39;s analogous to lazy-loading in web applications.</p></li></ol>`,63)])])}const m=e(n,[["render",d]]);export{u as __pageData,m as default};
